import React, { useState, useEffect } from "react";
import { signUpWithEmail, loginWithEmail, signInWithGoogle, logout, monitorAuthState } from "../firebase";
import { motion } from "framer-motion";

export default function Home() {
  const [isLogin, setIsLogin] = useState(true);
  const [user, setUser] = useState(null);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubscribe = monitorAuthState(setUser);
    return unsubscribe;
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (isLogin) {
        await loginWithEmail(email, password);
      } else {
        await signUpWithEmail(email, password);
      }
    } catch (err) {
      console.error(err);
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    setLoading(true);
    try {
      await signInWithGoogle();
    } catch (err) {
      console.error(err);
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await logout();
  };

  return (
    <div className="min-h-screen flex flex-col bg-primary text-light font-sans">
      {/* Hero / Branding */}
      <motion.header
        initial={{ opacity: 0, y: -30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7 }}
        className="flex flex-col items-center justify-center py-16 px-6 text-center"
      >
        <h1 className="text-4xl md:text-5xl font-bold text-light mb-4">
          The Grand Coordinating Enterprise
        </h1>
        <p className="text-md md:text-lg text-gray-300 max-w-2xl">
          A unified hub for innovation, creativity, and collaboration; connecting people, projects, and opportunities worldwide.
        </p>
      </motion.header>

      {/* Auth Section */}
      <motion.section
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.4, duration: 0.6 }}
        className="flex flex-col items-center justify-center flex-grow px-6"
      >
        {!user ? (
          <div className="w-full max-w-md bg-secondary rounded-2xl shadow-card p-8">
            <h2 className="text-2xl font-semibold text-light text-center mb-6">
              {isLogin ? "Login to Continue" : "Create Your Account"}
            </h2>

            <form onSubmit={handleSubmit} className="space-y-4">
              <input
                type="email"
                placeholder="Email Address"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full p-3 rounded-md bg-primary text-light placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-accent"
              />
              <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full p-3 rounded-md bg-primary text-light placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-accent"
              />
              <button
                type="submit"
                disabled={loading}
                className="w-full py-3 bg-accent text-white font-semibold rounded-md hover:bg-blue-500 transition"
              >
                {loading ? "Processing..." : isLogin ? "Login" : "Sign Up"}
              </button>
            </form>

            <button
              onClick={handleGoogle}
              className="w-full py-3 mt-4 border border-accent text-accent font-medium rounded-md hover:bg-accent hover:text-white transition"
            >
              Continue with Google
            </button>

            <p className="text-center text-sm text-gray-400 mt-4">
              {isLogin ? "New here?" : "Already have an account?"}{" "}
              <button
                onClick={() => setIsLogin(!isLogin)}
                className="text-accent hover:underline"
              >
                {isLogin ? "Create account" : "Login"}
              </button>
            </p>
          </div>
        ) : (
          <div className="text-center space-y-6">
            <h2 className="text-3xl font-semibold text-light">
              Welcome, {user.email}
            </h2>
            <p className="text-gray-300">
              You’re now logged in to the Godemar’s Empire community.
            </p>
            <button
              onClick={handleLogout}
              className="px-6 py-3 bg-accent text-white rounded-lg hover:bg-blue-500 transition"
            >
              Logout
            </button>
          </div>
        )}
      </motion.section>

      {/* Footer */}
      <footer className="bg-secondary py-6 mt-12 text-center text-gray-400 text-sm">
        © {new Date().getFullYear()} Godemar’s Empire. All rights reserved.
      </footer>
    </div>
  );
}
